import{_ as t,o as a,c as i,a3 as n}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"Tenant RBAC — Production Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Tenant RBAC — Production Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/deployment/tenant-rbac"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Tenant RBAC — Production Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/deployment/tenant-rbac"}]]},"headers":[],"relativePath":"deployment/tenant-rbac.md","filePath":"deployment/tenant-rbac.md","lastUpdated":1784403917000}'),o={name:"deployment/tenant-rbac.md"};function s(r,e,l,d,c,p){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="tenant-rbac-—-production-guide" tabindex="-1">Tenant RBAC — Production Guide <a class="header-anchor" href="#tenant-rbac-—-production-guide" aria-label="Permalink to &quot;Tenant RBAC — Production Guide&quot;">​</a></h1><p>Operational and security notes for workspace-isolated RBAC.</p><h2 id="security-invariants" tabindex="-1">Security invariants <a class="header-anchor" href="#security-invariants" aria-label="Permalink to &quot;Security invariants&quot;">​</a></h2><ol><li><strong>Workspace isolation</strong> — Tenancy middleware + <code>roles.tenant_id</code> ensure users/roles never leak across workspaces.</li><li><strong>Module licensing</strong> — <code>module:{slug}</code> must stay in front of product routes; permissions alone must not unlock unlicensed modules.</li><li><strong>RBAC</strong> — Prefer role→permission grants; avoid direct user permissions unless there is a documented exception.</li><li><strong>Guard separation</strong> — Tenant (<code>tenant-api</code> / <code>User</code>) and Central (<code>central-api</code> / <code>CentralUser</code>) credentials never interchange.</li><li><strong>Owner protection</strong> — Do not allow deleting the Owner role or the last Owner without an explicit product rule.</li></ol><h2 id="implementation-checklist" tabindex="-1">Implementation checklist <a class="header-anchor" href="#implementation-checklist" aria-label="Permalink to &quot;Implementation checklist&quot;">​</a></h2><ul><li>[ ] <code>config/tenant-permissions.php</code> lists every tenant permission used in routes/policies/UI</li><li>[ ] New workspaces provision roles via <code>TenantAuthorizationProvisioningService</code> with <code>tenant_id</code> set before owner creation</li><li>[ ] New permissions ship in additive data migrations; login never repairs RBAC</li><li>[ ] Role sync uses Role <strong>models</strong>, not bare names</li><li>[ ] Policies deny cross-tenant subjects even if IDs collide</li><li>[ ] Product routes use <code>module:</code> + <code>can:</code> together</li><li>[ ] SPA tenant nav items gated by the same permission names as the API</li></ul><h2 id="operational-risks" tabindex="-1">Operational risks <a class="header-anchor" href="#operational-risks" aria-label="Permalink to &quot;Operational risks&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Risk</th><th>Mitigation</th></tr></thead><tbody><tr><td>Assigning roles by name across tenants</td><td>Always resolve roles with <code>tenant_id</code></td></tr><tr><td>Enabling Spatie teams without migration</td><td>Keep custom <code>tenant_id</code> until pivots use UUID team keys</td></tr><tr><td>Privilege escalation</td><td>Policies block self-escalation / Owner self-delete where defined; audit role updates</td></tr><tr><td>Stale permission cache</td><td>Data migrations and provisioning clear Spatie&#39;s permission cache</td></tr><tr><td>Incomplete deploy “fixed” on login</td><td>Forbidden — auth has no RBAC side effects; ship additive permission migrations</td></tr></tbody></table><h2 id="maintenance" tabindex="-1">Maintenance <a class="header-anchor" href="#maintenance" aria-label="Permalink to &quot;Maintenance&quot;">​</a></h2><p>Legacy shared roles (<code>tenant_id</code> null) — explicit only:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tenants:isolate-roles</span></span></code></pre></div><p>Do not expect role listing or dashboard to backfill isolation.</p><h2 id="monitoring" tabindex="-1">Monitoring <a class="header-anchor" href="#monitoring" aria-label="Permalink to &quot;Monitoring&quot;">​</a></h2><ul><li>Audit role and user mutations (activity log where enabled)</li><li>Alert on repeated 403s on admin APIs (possible probing)</li><li>After permission catalog changes, re-run Pest isolation + Playwright <code>test:e2e:tenant-rbac</code></li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/developer-guide/tenant-rbac">Developer guide</a></li><li><a href="/user-guide/tenant-rbac">User guide</a></li><li><a href="/developer-guide/entitlements">Entitlements</a></li></ul>',16)])])}const m=t(o,[["render",s]]);export{u as __pageData,m as default};
